const input = $json || {};

function clean(value, max = 2000) {
  return String(value ?? "").trim().slice(0, max);
}

const text = clean(input.message_text || input.text || input.message || "");
const telegramUserId = clean(input.user_id || input.telegram_user_id || input.from_user_id || "", 80);
const telegramChatId = clean(input.chat_id || input.telegram_chat_id || "", 80);
const messageId = clean(input.message_id || "", 80);
const userName = clean(input.user_name || input.telegram_user_name || "", 120);
const errors = [];

if (!text) errors.push("message_text is required");
if (!telegramUserId) errors.push("user_id is required");
if (!telegramChatId) errors.push("chat_id is required");

if (errors.length > 0) {
  return [{
    json: {
      success: false,
      send_allowed: false,
      status: "invalid_relay_input",
      errors,
      sends_telegram: false,
      can_trigger_outbound_llm: false,
      writes: false,
      records_audit_trace: false,
    },
  }];
}

return [{
  json: {
    success: true,
    status: "normalized",
    text,
    telegram_user_id: telegramUserId,
    telegram_chat_id: telegramChatId,
    message_id: messageId,
    user_name: userName,
    gateway_payload: {
      text,
      telegram_user_id: telegramUserId,
      telegram_chat_id: telegramChatId,
      session_id: `telegram-${telegramChatId}`,
      source: "n8n_gatekeeper_private_relay",
    },
  },
}];

const item = $json || {};
if (item.success !== true) return [{ json: item }];

function baseUrlIsLocalOrTls(value) {
  try {
    const parsed = new URL(value);
    if (parsed.protocol === "https:") return true;
    if (parsed.protocol !== "http:") return false;
    return new Set(["127.0.0.1", "localhost", "[::1]"]).has(parsed.hostname);
  } catch (error) {
    return false;
  }
}

const baseUrl = String($env.OOM_SAKKIE_GATEWAY_BASE_URL || "").trim().replace(/\/+$/, "");
const token = String($env.OOM_SAKKIE_TELEGRAM_GATEWAY_TOKEN || "").trim();
const errors = [];

if (!baseUrl) errors.push("OOM_SAKKIE_GATEWAY_BASE_URL is required");
if (baseUrl && !baseUrlIsLocalOrTls(baseUrl)) errors.push("OOM_SAKKIE_GATEWAY_BASE_URL must use https, or local http on localhost/127.0.0.1/::1");
if (token.length < 32) errors.push("OOM_SAKKIE_TELEGRAM_GATEWAY_TOKEN must be at least 32 characters");

if (errors.length > 0) {
  return [{
    json: {
      ...item,
      success: false,
      send_allowed: false,
      status: "relay_env_not_ready",
      errors,
      sends_telegram: false,
      can_trigger_outbound_llm: false,
      writes: false,
      records_audit_trace: false,
    },
  }];
}

return [{
  json: {
    ...item,
    gateway_url: `${baseUrl}/api/oom-sakkie/channels/telegram/message`,
    gateway_token: token,
  },
}];
